        return s

    start_index = -1
    end_index = -1

    # Find first occurrence
    for i, c in enumerate(s):
        if c == char:
            start_index = i
            break

    # Find last occurrence
    for i in range(len(s) - 1, -1, -1):
        if s[i] == char:
            end_index = i
            break

    # If no occurrences found, return original string
    if start_index == -1:
        return s

    # If first and last are the same (only one occurrence), remove it
    if start_index == end_index:
        return s[:start_index] + s[start_index+1:]

    # Remove both first and last occurrence
    return s[:start_index] + s[start_index+1:end_index] + s[end_index+1:]

