def binary_to_decimal(binary_str: str) -> int:
    """
    Convert a binary string to its decimal equivalent.

    Args:
        binary_str (str): A string representing a binary number.

    Returns:
        int: The decimal equivalent of the binary number.

    Raises:
        ValueError: If the input string contains invalid characters.
    """
    if not binary_str:
        return 0

    try:
        return int(binary_str, 2)
    except ValueError:
        raise ValueError("Invalid binary string. Must contain only '0' and '1'.")

