import heapq

def func(lists, k):
    freq_map = {}
    for lst in lists:
        for num in lst:
            freq_map[num] = freq_map.get(num, 0) + 1

    # Use a min-heap to keep track of the top k elements
    heap = []
    for num, freq in freq_map.items():
        heapq.heappush(heap, (freq, num))
        if len(heap) > k:
            heapq.heappop(heap)

    # Extract elements from the heap
    result = [num for _, num in heap]
    return sorted(result)

import heapq

class CountHeap:
    def __init__(self):
        self.heap = []

    def add(self, count, num):
        # Use negative count for max-heap behavior
        heapq.heappush(self.heap, (-count, num))

    def get_top_k(self, k):
        result = []
        for _ in range(k):
            if not self.heap:
                break
            count, num = heapq.heappop(self.heap)
            result.append(num)
        return result

def func(lists, k):
    count_heap = CountHeap()

    # Count frequencies of all integers across all lists
    all_numbers = []
    for lst in lists:
        all_numbers.extend(lst)

    # Use a frequency map
    from collections import Counter
    counts = Counter(all_numbers)

    # Add to heap
    for num, count in counts.items():
        count_heap.add(count, num)

    # Get top k
    return count_heap.get_top_k(k)

