def bell_number(n):
    if n == 0:
        return 1
    if n == 1:
        return 1

    # Initialize Bell triangle
    # B(n, k) = B(n-1, k-1) + B(n-1, k)
    # We only need the last row to compute the next row
    prev_row = [1]

    for i in range(1, n + 1):
        current_row = []
        for j in range(i + 1):
            if j == 0:
                current_row.append(prev_row[-1])
            else:
                current_row.append(prev_row[j-1] + prev_row[j])
        prev_row = current_row

    return prev_row[0]

