def bell_number(n):
    if n < 0:
        return 0
    if n == 0:
        return 1

    bell = [0] * (n + 1)
    bell[0] = 1

    for i in range(1, n + 1):
        bell[i] = 0
        for j in range(i):
            bell[i] += bell[j] * binomial_coefficient(i - 1, j)

    return bell[n]

def binomial_coefficient(n, k):
    if k < 0 or k > n:
        return 0
    if k == 0 or k == n:
        return 1
    if k > n // 2:
        k = n - k

    result = 1
    for i in range(k):
        result = result * (n - i) // (i + 1)
    return result

def bell_number(n):
    """Calculate the nth Bell number, which is the number of partitions of a set with n elements."""
    if n < 0:
        raise ValueError("Input must be a non-negative integer")

    # Initialize Bell triangle
    bell_triangle = [[0] * (n + 1)]
    bell_triangle[0].append(1)

    for i in range(1, n + 1):
        row = []
        for j in range(i + 1):
            if j == 0:
                row.append(bell_triangle[i-1][j-1]) if j > 0 else bell_triangle[i-1][-1]
            else:
                row.append(bell_triangle[i-1][j-1] + bell_triangle[i-1][j])
        bell_triangle.append(row)

    return bell_triangle[n][n]

