def count_Squares(width, height):
    if width <= 0 or height <= 0:
        return 0

    total_squares = 0
    # Count squares of each possible size
    for size in range(1, min(width, height) + 1):
        # Number of positions for a square of size 'size' in a grid of dimensions width x height
        num_positions = (width - size + 1) * (height - size + 1)
        total_squares += num_positions

    return total_squares

def count_Squares(width, height):
    count = 0
    for i in range(1, width + 1):
        for j in range(1, height + 1):
            if i <= width and j <= height:
                # Check if a square of size i x i can fit in a grid of width x height
                # We need to count how many positions a square of size i x i can be placed in
                # The number of positions is (width - i + 1) * (height - i + 1) if width >= i and height >= i
                if i <= width and i <= height:
                    count += (width - i + 1) * (height - i + 1)
    return count

