def is_Diff(n):
    even_sum = 0
    odd_sum = 0

    # Handle negative numbers by taking absolute value
    n = abs(n)

    while n > 0:
        digit = n % 10
        if digit % 2 == 0:
            even_sum += digit
        else:
            odd_sum += digit
        n //= 10

    return even_sum == odd_sum

