def sequence(n):
    if n == 1:
        return 1

    memo = {1: 1}

    def helper(k):
        if k in memo:
            return memo[k]

        prev = helper(k - 1)
        prev_prev = helper(k - prev)
        result = prev + prev_prev
        memo[k] = result
        return result

    return helper(n)

