def merge_sorted_list(*lists: List[int]) -> List[int]:
    if not lists:
        return []

    # Create a heap of iterators, storing (current_value, list_index, iterator_index)
    heap = []
    for i, lst in enumerate(lists):
        if lst:
            heapq.heappush(heap, (lst[0], i, 0))

    result = []

    while heap:
        value, list_idx, item_idx = heapq.heappop(heap)
        result.append(value)

        # Get the next element from the same list if available
