def tuple_to_int(tup):
    """
    Converts a tuple of positive integers into an integer.

    Args:
        tup (tuple): A tuple of positive integers.

    Returns:
        int: The integer formed by concatenating the digits of the tuple elements.

    Raises:
        ValueError: If the input is not a tuple or contains non-positive integers.
    """
    if not isinstance(tup, tuple):
        raise TypeError("Input must be a tuple.")

    for item in tup:
        if not isinstance(item, int) or item <= 0:
            raise ValueError("All elements must be positive integers.")

    return int(''.join(map(str, tup)))

