def check_triplet(arr, sum1, sum2, sum3):
    """
    Check if there exist three distinct elements in the array whose sum equals sum1 + sum2 + sum3.
    """
    target = sum1 + sum2 + sum3
    n = len(arr)
    if n < 3:
        return False

    arr_sorted = sorted(arr)

    for i in range(n - 2):
        if i > 0 and arr_sorted[i] == arr_sorted[i - 1]:
            continue

        left = i + 1
        right = n - 1

        while left < right:
            current_sum = arr_sorted[i] + arr_sorted[left] + arr_sorted[right]

            if current_sum == target:
                return True
            elif current_sum < target:
                left += 1
            else:
                right -= 1

    return False

