def amicable_numbers_sum(n):
    def get_divisors(num):
        divisors = set()
        for i in range(1, int(num**0.5) + 1):
            if num % i == 0:
                divisors.add(i)
                divisors.add(num // i)
        return divisors

    def get_sum_of_divisors(num):
        return sum(get_divisors(num))

    def is_amicable(a, b):
        if a == b:
            return False
        sum_a = get_sum_of_divisors(a)
        sum_b = get_sum_of_divisors(b)
        return sum_a == b and sum_b == a

    amicable_numbers = set()
    for i in range(1, n + 1):
        sum_i = get_sum_of_divisors(i)
        if sum_i != i and sum_i <= n:
            if is_amicable(i, sum_i):
                amicable_numbers.add(i)
                amicable_numbers.add(sum_i)

    return sum(amicable_numbers)

