def is_Sum_Of_Powers_Of_Two(n):
    def is_power_of_two(num):
        return num > 0 and (num & (num - 1)) == 0

    def can_be_represented_as_sum_of_powers_of_two(num):
        if num <= 0:
            return False
        while num > 0:
            if is_power_of_two(num):
                num -= num
            else:
                return False
        return True

    return can_be_represented_as_sum_of_powers_of_two(n)

