def extract_singly(tuples_list):
    from collections import defaultdict

    # Count occurrences of each element across all tuples
    element_counts = defaultdict(int)
    for t in tuples_list:
        for element in t:
            element_counts[element] += 1

    # Extract elements that occur exactly once
    result = [element for element in tuples_list for count in element_counts.values() if count == 1]
    return result

