    for i in range(1, len(str(n))):
        left_part = n // (10 ** i)
        right_part = n % (10 ** i)

        def sum_digits(num):
            s = 0
            while num > 0:
                s += num % 10
                num //= 10
            return s

        total_sum = sum_digits(left_part) + sum_digits(right_part)
        if total_sum > max_sum:
            max_sum = total_sum

    return max_sum

