def longest_subseq_with_diff_one(arr, max_length):
    if not arr:
        return 0

    # dp[i] = length of longest subsequence ending at index i with diff 1
    dp = [1] * len(arr)
    for i in range(1, len(arr)):
        for j in range(i):
            if arr[i] - arr[j] == 1:
                dp[i] = max(dp[i], dp[j] + 1)

    # dp2[i] = length of longest subsequence ending at index i with diff -1
    dp2 = [1] * len(arr)
    for i in range(1, len(arr)):
        for j in range(i):
            if arr[i] - arr[j] == -1:
                dp2[i] = max(dp2[i], dp2[j] + 1)

    # Combine results: find longest chain that alternates between +1 and -1 differences
    # We use a DP state: dp[i][0] = max length ending at i with last diff +1
    # dp[i][1] = max length ending at i with last diff</think>

def longest_subseq_with_diff_one(arr, max_length):
    if not arr:
        return 0

    n = len(arr)
    # dp[i][0] = longest subsequence ending at index i with last diff = +1
    # dp[i][1] = longest subsequence ending at index i with last diff = -1
    dp = [[0, 0] for _ in range(n)]

    for i in range(n):
        dp[i][0] = 1  # Start a new subsequence with diff +1
        dp[i][1] = 1  # Start a new subsequence with diff -1

    for i in range(1, n):
        # Try to extend a subsequence with last diff = -1 to get diff = +1
        for j in range(i):
            if arr[i] - arr[j] == 1:
                dp[i][0] = max(dp[i][0], dp[j][1] + 1)
        # Try to extend a subsequence with last diff = +1 to get diff = -1
        for j in range(i):
            if arr[i] - arr[j] == -1:
                dp[i][1] = max(dp[i][1], dp[j][0] + 1)

    # Find the maximum length from any ending state
    result = max(max(row) for row in dp)
    return result if result <= max_length else max_length

