        if n < 2:
            return 0
        total = 1
        for i in range(2, int(n ** 0.5) + 1):
            if n % i == 0:
                total += i
                if i != n // i:
                    total += n // i
        return total

    return sum_of_divisors(a) == sum_of_divisors(b)

