def count_char_position(s):
    if not s:
        return 0

    first_char = s[0]
    first_pos = ord(first_char) - ord('a') if first_char.isalpha() else ord(first_char) - ord('A')

    count = 1
    for char in s[1:]:
        if char.isalpha():
            current_pos = ord(char) - ord('a') if char.islower() else ord(char) - ord('A')
            if current_pos == first_pos:
                count += 1

    return count


