def is_num_keith(n):
    def keith_sequence(n):
        if n <= 0:
            return []
        sequence = [n]
        while len(sequence) <= len(sequence) - 1:
            next_val = sum(sequence[-len(sequence):])
            if next_val in sequence:
                break
            sequence.append(next_val)
        return sequence

    sequence = keith_sequence(n)
    return n in sequence and len(sequence) == n

