class CharacterCounter:
    def __init__(self):
        self.uppercase = []
        self.lowercase = []
        self.special = []
        self.numeric = []

    def count(self, text):
        self.uppercase = [char for char in text if char.isupper()]
        self.lowercase = [char for char in text if char.islower()]
        self.numeric = [char for char in text if char.isdigit()]
        self.special = [char for char in text if not char.isalnum()]
        return [self.uppercase, self.lowercase, self.special, self.numeric]

def find_character(text):
    counter = CharacterCounter()
    return counter.count(text)

