def count_pairs(arr, k):
    if k < 0:
        return 0
    seen = set()
    distinct_pairs = set()
    for num in arr:
        if (num - k) in seen or (num + k) in seen:
            distinct_pairs.add(frozenset({num, num + k}))
        seen.add(num)
    return len(distinct_pairs)

