    n = len(s)
    if n == 0:
        return 0

    # dp[i][j] will store the length of the longest repeating subsequence
    # using characters from s[0..i-1] and s[0..j-1]
    # We only care about i < j to avoid comparing the same character at the same position
    dp = [[0] * (n + 1) for _ in range(n + 1)]

    for i in range(1, n + 1):
        for j in range(i + 1, n + 1):
            if s[i - 1] == s[j - 1]:
                dp[i][j] = dp[i - 1][j - 1] + 1
            else:
                dp[i][j] = max(dp[i - 1][j], dp[i][j - 1])

    return dp[n][n]

