def is_majority(arr, n, k):
    if n < k:
        return False

    # Since the array is sorted, we can use binary search to find the first occurrence of k
    left, right = 0, n - 1
    first_occurrence = -1

    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == k:
            first_occurrence = mid
            right = mid - 1
        elif arr[mid] < k:
            left = mid + 1
        else:
            right = mid - 1

    if first_occurrence == -1:
        return False

    # Check if the count of k is at least k
    # Since it's sorted, all k's are together
    # Count how many times k appears
    count = 0
    for i in range(n):
        if arr[i] == k:
            count += 1
        else:
            break

    return count >= k

