    """
    Finds the length of the longest palindromic subsequence in the given string.
    """
    n = len(s)
    if n == 0:
        return 0

    dp = [[0] * n for _ in range(n)]

    # Every single character is a palindrome of length 1
    for i in range(n):
        dp[i][i] = 1

