def is_newman_prime(n):
    """Check if n is a Newman-Shanks-Williams prime."""
    if n < 2:
        return False
    if n % 2 == 0:
        return False

    # Check divisibility by small primes
    for i in range(3, int(math.sqrt(n)) + 1, 2):
        if n % i == 0:
            return False

    return True

def newman_prime(n):
    """Find the nth Newman-Shanks-Williams prime number."""
    count = 0
    candidate = 2

    while True:
        if is_newman_prime(candidate):
            count += 1
            if count == n:
                return candidate
        candidate += 1

