def validate(n):
    """
    Check whether the frequency of each digit is less than or equal to the digit itself.

    Args:
        n (int): The number to validate.

    Returns:
        bool: True if the condition is met for all digits, False otherwise.
    """
    if not isinstance(n, int):
        raise TypeError("Input must be an integer.")

    if n < 0:
        raise ValueError("Input must be a non-negative integer.")

    digit_counts = {}

    # Count frequency of each digit
    for digit in str(n):
        d = int(digit)
        digit_counts[d] = digit_counts.get(d, 0) + 1

    # Check condition: frequency <= digit
    for digit, count in digit_counts.items():
        if count > digit:
            return False

    return True

