def modular_inverse(arr, p, mod):
    count = 0
    for x in arr:
        if x % mod == 0:
            continue
        # Find modular inverse of x modulo p
        # Using Fermat's Little Theorem: x^(p-2) mod p
        inv = pow(x, mod - 2, p)
        if inv == x % p:
            count += 1
    return count

def modular_inverse(arr, p):
    def extended_gcd(a, b):
        if a == 0:
            return b, 0, 1
        gcd, x1, y1 = extended_gcd(b % a, a)
        x = y1 - (b // a) * x1
        y = x1
        return gcd, x, y

    def mod_inverse_element(x, p):
        if x == 0:
            return None
        g, x, _ = extended_gcd(x, p)
        if g != 1:
            return None
        return (x % p + p) % p

    count = 0
    for num in arr:
        if 0 <= num < p:
            inv = mod_inverse_element(num, p)
            if inv is not None and inv == num:
                count += 1
    return count

