        if a == 0:
            return b, 0, 1
        else:
            gcd, x, y = extended_gcd(b % a, a)
            return gcd, y - (b // a) * x, x

    def is_modular_inverse_equal_to_self(n, p):
        if n % p == 0:
            return False
        gcd, x, _ = extended_gcd(n, p)
        if gcd != 1:
            return False
        inv = (x % p + p) % p
        return inv == n

    count = 0
    for num in arr:
        if is_modular_inverse_equal_to_self(num % p, p):
            count += 1
    return count

