def count_binary_seq(n):
    """
    Count the number of binary sequences of length 2n such that 
    the sum of the first n bits equals the sum of the last n bits.

    This is equivalent to choosing k positions for 1s in the first n bits,
    and choosing the same k positions for 1s in the last n bits,
    where k ranges from 0 to n.

    The count is sum(C(n, k)^2) for k from 0 to n.
    By Vandermonde's Identity, this equals C(2n, n).
    """
    import math

    def factorial(x):
        result = 1
        for i in range(2, x + 1):
            result *= i
        return result

    def combination(n, k):
        if k < 0 or k > n:
            return 0
        return factorial(n) // (factorial(k) * factorial(n - k))

    return combination(2 * n, n)

