def set_left_most_unset_bit(n):
    # Convert n to binary string, remove '0b' prefix
    binary = bin(n)[2:]

    # Find the leftmost '0' bit
    for i in range(len(binary) - 1, -1, -1):
        if binary[i] == '0':
            # Set this bit to '1'
            binary_list = list(binary)
            binary_list[i] = '1'
            return int("".join(binary_list), 2)

    # If no '0' bit is found, it means all bits are '1'
    # In this case, we need to extend the binary string with a new '0' at the front
    return int("0" + binary, 2)

