def max_sum_rectangular_grid(grid, n):
    if n == 0:
        return 0
    if n == 1:
        return max(grid[0][0], grid[1][0])

    # dp[0] = max sum ending at current column with row 0 picked
    # dp[1] = max sum ending at current column with row 1 picked
    # dp[2] = max sum ending at current column with neither picked

    dp = [grid[0][0], grid[1][0], 0]

    for i in range(1, n):
        new_dp = [0, 0, 0]
        new_dp[0] = max(dp[1], dp[2]) + grid[0][i]
        new_dp[1] = max(dp[0], dp[2]) + grid[1][i]
        new_dp[2] = max(dp[0], dp[1], dp[2])
