def max_volume(n):
    if n <= 0:
        return 0

    # We want to maximize V = l * w * h subject to 2*(l + w + h) = n
    # So l + w + h = n/2
    # Let s = n/2. We want to maximize l*w*h given l+w+h=s.
    # The maximum occurs when l=w=h=s/3 (for real numbers).
    # Since l, w, h must be integers, we check integer partitions of s into 3 parts.

    s = n // 2
    if s < 3:
        return 0

    max_v = 0

    # Iterate over possible values for l
    for l in range(1, s // 2 + 1):
        # Remaining sum for w + h
        rem = s - l
        if rem < 2:
            continue

        # Iterate over possible values for w
        for w in range(1, rem // 2 + 1):
            h = rem - w
            if h < 1:
                continue

