def get_Min_Squares(n):
    """
    Returns the minimum number of perfect square numbers that sum to n.
    Uses dynamic programming with memoization.
    """
    memo = {}

    def dp(num):
        if num == 0:
            return 0
        if num in memo:
            return memo[num]

        min_squares = num  # Worst case: all 1s
        for i in range(1, int(num**0.5) + 1):
            square = i * i
            if square > num:
                break
            count = 1 + dp(num - square)
            if count < min_squares:
                min_squares = count

        memo[num] = min_squares
        return min_squares

    return dp(n)

def get_Min_Squares(n):
    def dp(i):
        if i == 0:
            return 0
        if memo[i] != -1:
            return memo[i]
        res = i
        for j in range(1, int(i**0.5) + 1):
            res = min(res, 1 + dp(i - j*j))
        memo[i] = res
        return res

    memo = [-1] * (n + 1)
    return dp(n)

def get_Min_Squares(n):
    if n == 0:
        return 0

    # Square numbers up to n
    squares = [i*i for i in range(1, int(n**0.5) + 1)]

    # dp[i] will store the minimum number of squares whose sum is i
    dp = [float('inf')] * (n + 1)
    dp[0] = 0

    for i in range(1, n + 1):
        for square in squares:
            if square <= i:
                dp[i] = min(dp[i], dp[i - square] + 1)

    return dp[n]

