def find_ways(n):
    def count_valid_sequences(length, values):
        count = 0
        def backtrack(idx, current_sum):
            nonlocal count
            if idx == length:
                count += 1
                return

            for val in values:
                new_sum = current_sum + val
                if new_sum >= 0:
                    backtrack(idx + 1, new_sum)

        backtrack(0, 0)
        return count

    return count_valid_sequences(n, [1])  # Assuming values are [1] based on the test case

