def find_ways(n: int) -> int:
    """
    Count sequences of length n with non-negative prefix sums
    generated by values {-1, 1}.

    This is equivalent to counting Dyck paths of semi-length n,
    which is given by the Catalan number C_n = (2n)! / ((n+1)! * n!).
    """
    if n < 0:
        return 0
    return catalan(n)


def catalan(n: int) -> int:
    """Compute the nth Catalan number."""
    # Using integer arithmetic to avoid floating point issues
    # C_n = (2n)! / ((n+1)! * n!)
    # We can compute this iteratively or using factorials.
    # For larger n, we might need big integers, which Python handles automatically.

    # Iterative approach: C_0 = 1, C_{n+1} = sum_{i=0 to n} C_i * C_{n-i}
    # Or more efficiently: C_n = (2n)! / ((n+1)! * n!)
    # We'll compute factorials and divide</think>

def find_ways(n: int) -> int:
    if n < 0:
        return 0
    return catalan(n)


def catalan(n: int) -> int:
    # Compute nth Catalan number using formula: C_n = (2n)! / ((n+1)! * n!)
    # Python handles large integers automatically.
    two_n_fact = 1
    for i in range(1, 2 * n + 1):
        two_n_fact *= i

    n_plus_1_fact = 1
    for i in range(1, n + 2):
        n_plus_1_fact *= i

    n_fact = 1
    for i in range(1, n + 1):
        n_fact *= i

    return two_n_fact // (n_plus_1_fact * n_fact)

