def _sift_down(heap, startpos, pos):
    newitem = heap[startpos]
    while startpos < pos:
        childpos = 2 * startpos + 1
        if childpos < pos:
            rightpos = childpos + 1
            if rightpos < pos and heap[childpos] < heap[rightpos]:
                childpos = rightpos
            heap[startpos] = heap[childpos]
            startpos = childpos
        else:
            break
    heap[startpos] = newitem

