def permute_string(s: str) -> list[str]:
    if len(s) <= 1:
        return [s]

    result = []
    chars = list(s)

    def backtrack(path, used):
        if len(path) == len(chars):
            result.append(''.join(path))
            return

        for i in range(len(chars)):
            if used[i]:
                continue

            if i > 0 and chars[i] == chars[i-1] and not used[i-1]:
                continue

            used[i] = True
            path.append(chars[i])
            backtrack(path, used)
            path.pop()
            used[i] = False

    backtrack([], [False] * len(chars))
    return result

