def get_perrin(n):
    """
    Calculate the n'th Perrin number using recursion.
    The Perrin sequence is defined as:
    P(n) = P(n-2) + P(n-3) for n > 12
    with base cases: P(0) = 3, P(1) = 0, P(2) = 2.
    """
    if n == 0:
        return 3
    elif n == 1:
        return 0
    elif n == 2:
        return 2
    else:
        return get_perrin(n - 2) + get_perrin(n - 3)

