def swap_count(s: str) -> int:
    """
    Calculates the minimum number of swaps required to balance the brackets in the string.
    """
    open_count = 0
    swap_count = 0

    # First pass: count the number of ']' that need to be swapped
    for char in s:
        if char == '[':
            open_count += 1
        elif char == ']':
            if open_count > 0:
                open_count -= 1
            else:
                swap_count += 1

    return swap_count

def swap_count(s: str) -> int:
    stack = []
    open_count = 0
    close_count = 0

    for char in s:
        if char == '(':
            stack.append('(')
            open_count += 1
        elif char == ')':
            if stack and stack[-1] == '(':
                stack.pop()
                open_count -= 1
            else:
                close_count += 1
        else:
            raise ValueError("Invalid character in string")

    return open_count + close_count

