def get_max_sum(n):
    memo = {}

    def helper(n):
        if n == 0:
            return 0
        if n in memo:
            return memo[n]

        # Calculate the sum of recursive calls
        recursive_sum = helper(n // 2) + helper(n // 3) + helper(n // 4) + helper(n // 5)

        # The result is the maximum of the recursive sum and n itself
        result = max(recursive_sum, n)

        memo[n] = result
        return result

    return helper(n)

