def add_nested_tuples(t1, t2):
    if len(t1) != len(t2):
        raise ValueError("Tuples must have the same length.")

    result = []
    for i in range(len(t1)):
        t1_i = t1[i]
        t2_i = t2[i]
        if len(t1_i) != len(t2_i):
            raise ValueError(f"Inner tuples at index {i} must have the same length.")
        result.append((t1_i[j] + t2_i[j] for j in range(len(t1_i))))
    return tuple(result)

