def rearrange_bigger(n):
    if n < 0:
        return -rearrange_bigger(-n)

    s = list(str(n))
    digits = [int(d) for d in s]

    if not digits:
        return 0

    # Find the first digit from the right that is smaller than the digit to its right
    i = len(digits) - 2
    while i >= 0 and digits[i] >= digits[i + 1]:
        i -= 1

    if i == -1:
        # No such digit found, no bigger number can be formed
        return n

    # Swap the found digit with the smallest digit greater than it to its right
    j = len(digits) - 1
    while digits[j] <= digits[i]:
        j -= 1
    digits[i], digits[j] = digits[j], digits[i]

    # Reverse the suffix after the swapped digit
    digits[i+1:] = digits[i+1:][::-1]

    return int("".join(map(str, digits)))

